// Get the AI response from the HTTP Request node
const aiResponse = items[0].json.choices[0].message.content;

// Parse the JSON from the AI's response
let parsed;
try {
  parsed = JSON.parse(aiResponse);
} catch (e) {
  const cleaned = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
}

// Get original email data from the trigger node
const emailNode = $('Email Trigger (IMAP)').first();
const emailData = emailNode.json;

// --- THIS IS THE FIX ---
// Carry the binary file forward so the next node can see it
const binaryData = emailNode.binary;

return [{
  json: {
    senderName: parsed.senderName || emailData.from.value[0].name || '',
    senderEmail: emailData.from.value[0].address,
    subject: emailData.subject,
    body: emailData.text,
    category: parsed.category,
    priority: parsed.priority || 'Normal',
    fullName: parsed.fullName,
    phone: parsed.phone,
    summary: parsed.summary,
    extractedSkills: parsed.extractedSkills || [],
    education: parsed.education,
    experienceYears: parsed.experienceYears || 0,
    certifications: parsed.certifications || [],
    languages: parsed.languages || [],
    portfolioLinks: parsed.portfolioLinks || [],
    recommendationLevel: parsed.recommendationLevel,
    jobId: "" 
  },
  binary: binaryData // This passes the CV file to the final HTTP node
}];

